/**
 * Parity tests for the TS orthography compiler vs the Rust personality_steering
 * scorer. Same emoji-hater witness: emoji demoted, `:)` promoted, envelope held.
 */

import { describe, it, expect } from 'vitest';
import {
  tokenStyleFeatures,
  orthographicAffinity,
  foldSigned,
  clampSym,
  compileBoundaryBias,
} from '../personality-orthography';
import type {
  PersonalityStylePreferences,
  PersonalitySteeringSignature,
} from '../types';

describe('token style features', () => {
  it('detects the tells', () => {
    expect(tokenStyleFeatures('HELLO').allCaps).toBe(true);
    expect(tokenStyleFeatures('Hello').allCaps).toBe(false);
    expect(tokenStyleFeatures('hello').allLower).toBe(true);
    expect(tokenStyleFeatures('wait…').hasEllipsis).toBe(true);
    expect(tokenStyleFeatures('really?').hasQuestion).toBe(true);
    expect(tokenStyleFeatures('no!').hasExclaim).toBe(true);
    expect(tokenStyleFeatures('done.').hasTerminalPeriod).toBe(true);
    expect(tokenStyleFeatures('done.').hasEllipsis).toBe(false);
    expect(tokenStyleFeatures(':)').hasAsciiEmoticon).toBe(true);
    expect(tokenStyleFeatures('😂').hasEmoji).toBe(true);
  });
});

describe('clampSym mirrors Lean/Rust', () => {
  it('two-sided envelope', () => {
    expect(clampSym(-30, 20)).toBe(-20);
    expect(clampSym(12, 20)).toBe(12);
    expect(clampSym(99, 20)).toBe(20);
    expect(clampSym(0, 20)).toBe(0);
  });
});

describe('emoji-hater compile', () => {
  const sig: PersonalitySteeringSignature = {
    behavioral_gain: 2,
    aesthetic_gain: 3,
    prosody_gain: 2,
    harmonic_gain: 1,
    steer_cap: 12,
    rest_cap: 3,
  };
  // Avoids emoji (negative), leans on :) (positive), lowercase.
  const prefs: PersonalityStylePreferences = {
    caps: -700,
    lower: 600,
    exclaim: -300,
    question: 0,
    ellipsis: 500,
    period: -500,
    emoji: -900,
    ascii_emoticon: 700,
  };

  it('emoji token folds negative, :) positive', () => {
    expect(foldSigned(sig, orthographicAffinity('😂', prefs))).toBeLessThan(0);
    expect(foldSigned(sig, orthographicAffinity(':)', prefs))).toBeGreaterThan(0);
  });

  it('compiled vector respects the envelope; emoji demoted, :) promoted', () => {
    // 'Hey' is mixed-case (no caps/lower tell) -> neutral; 'there' is lowercase.
    const vocab = ['Hey', '😂', ':)', 'there', 'HELLO'];
    const bias = compileBoundaryBias(prefs, sig, vocab);
    for (const b of bias) expect(Math.abs(b)).toBeLessThanOrEqual(sig.steer_cap!);
    expect(bias[0]).toBe(0); // 'Hey' has no scored tell -> neutral
    expect(bias[1]).toBeLessThan(0); // 😂 demoted
    expect(bias[2]).toBeGreaterThan(0); // :) promoted
    expect(bias[3]).toBeGreaterThan(0); // 'there' lowercase -> promoted
    expect(bias[4]).toBeLessThan(0); // HELLO demoted (caps anti-tell)
  });
});
